### Layout Component Pattern

Create reusable layouts to wrap pages. A layout is a React component that accepts `children`:

```jsx
// components/Layout.js
export default function Layout({ children }) {
  return (
    <div>
      <header>
        <nav>
          <a href="/">Home</a>
          <a href="/blog">Blog</a>
        </nav>
      </header>
      <main>{children}</main>
      <footer>&copy; 2024 My App</footer>
    </div>
  );
}
```

### Using Layout in Pages

Wrap each page's content with the layout:

```jsx
import Layout from '../components/Layout';

export default function Home() {
  return (
    <Layout>
      <h1>Home Page</h1>
    </Layout>
  );
}
```

### Custom App Component (_app.js)

Use `_app.js` to persist the layout across all pages:

```jsx
// pages/_app.js
import Layout from '../components/Layout';

export default function App({ Component, pageProps }) {
  return (
    <Layout>
      <Component {...pageProps} />
    </Layout>
  );
}
```

This avoids wrapping every page individually.

### Nested Layouts

For different sections with their own layouts, create a page-level layout:

```jsx
// pages/dashboard.js
export default function Dashboard({ children }) {
  return (
    <div>
      <aside>Dashboard sidebar</aside>
      <main>{children}</main>
    </div>
  );
}

// In _app.js, check if page has its own layout
function App({ Component, pageProps }) {
  const getLayout = Component.getLayout || ((page) => <Layout>{page}</layout>);
  return getLayout(<Component {...pageProps} />);
}
```

